const _ = require('lodash');

const CONSOLE = require('./console');

const STORAGE = {};

STORAGE.localStorage = _.assign({}, {
    /**
     * @memberof BXUI.Storage.localStorage
     */
    "get": (...args) =>{
        return _get.apply(STORAGE.localStorage, ['localStorage'].concat(args));
    },
    /**
     * @memberof BXUI.Storage.localStorage
     */
    "set": (...args) =>{
        return _set.apply(STORAGE.localStorage, ['localStorage'].concat(args));
    },
    /**
     * @memberof BXUI.Storage.localStorage
     */
    "remove": (...args) =>{
        return _remove.apply(STORAGE.localStorage, ['localStorage'].concat(args));
    },
    /**
     * @memberof BXUI.Storage.localStorage
     */
    "clear": (...args) =>{
        return _clear.apply(STORAGE.localStorage, ['localStorage'].concat(args));
    }
});

STORAGE.sessionStorage = _.assign({}, {
    /**
     * @memberof BXUI.Storage.sessionStorage
     */
    "get": (...args) =>{
        return _get.apply(STORAGE.sessionStorage, ['sessionStorage'].concat(args));
    },
    /**
     * @memberof BXUI.Storage.sessionStorage
     */
    "set": (...args) =>{
        return _set.apply(STORAGE.sessionStorage, ['sessionStorage'].concat(args));
    },
    /**
     * @memberof BXUI.Storage.sessionStorage
     */
    "remove": (...args) =>{
        return _remove.apply(STORAGE.sessionStorage, ['sessionStorage'].concat(args));
    },
    /**
     * @memberof BXUI.Storage.sessionStorage
     */
    "clear": (...args) =>{
        return _clear.apply(STORAGE.sessionStorage, ['sessionStorage'].concat(args));
    }
});

/**
 *
 * 아이템을 가져온다.
 *
 * @param {String} [type=''] - storage 타입
 * @param {String} [key='']
 *
 * @return 아이템
 *
 */
function _get(type = '', key = ''){

    if (type === 'localStorage' && !window['localStorage']){
        CONSOLE.prop.throw(STORAGE[type].get, 'type', 'all');
    }

    if (type === 'sessionStorage' && !window['sessionStorage']){
        CONSOLE.prop.throw(STORAGE[type].get, 'type', 'all');
    }

    if (!_.isString(key)){
        CONSOLE.prop.throw(STORAGE[type].get, 'key', 'all');
    }

    let storage = window[type];

    return storage.getItem(key);
}

/**
 *
 * 아이템을 저장한다.
 *
 * @param {String} [type=''] - storage 타입
 * @param {String} [key='']
 * @param [value=null]
 *
 * @return {object} BXUI.Storage 객체
 *
 */
function _set(type = '', key = '', value = null){

    if (type === 'localStorage' && !window['localStorage']){
        CONSOLE.prop.throw(STORAGE[type].set, 'type', 'all');
    }

    if (type === 'sessionStorage' && !window['sessionStorage']){
        CONSOLE.prop.throw(STORAGE[type].set, 'type', 'all');
    }

    if (!_.isString(key)){
        CONSOLE.prop.throw(STORAGE[type].set, 'key', 'all');
    }

    if (_.isNull(value)){
        CONSOLE.prop.throw(STORAGE[type].set, 'value', 'all');
    }

    let storage = window[type];

    storage.setItem(key, value);

    return this;
}

/**
 *
 * 정해진 아이템을 삭제한다
 *
 * @param {String} [type=''] - storage 타입
 * @param {String} [key='']
 *
 * @return {object} BXUI.Storage 객체
 *
 */
function _remove(type = '', key = ''){


    if (type === 'localStorage' && !window['localStorage']){
        CONSOLE.prop.throw(STORAGE[type].remove, 'type', 'all');
    }

    if (type === 'sessionStorage' && !window['sessionStorage']){
        CONSOLE.prop.throw(STORAGE[type].remove, 'type', 'all');
    }

    if (!_.isString(key)){
        CONSOLE.prop.throw(STORAGE[type].remove, 'key', 'all');
    }

    let storage = window[type];

    storage.removeItem(key);

    return this;
}

/**
 *
 * 모든 아이템을 삭제한다
 *
 * @param {String} [type=''] - storage 타입
 *
 * @return {object} BXUI.Storage 객체
 *
 */
function _clear(type = ''){

    if (type === 'localStorage' && !window['localStorage']){
        CONSOLE.prop.throw(STORAGE[type].clear, 'type', 'all');
    }

    if (type === 'sessionStorage' && !window['sessionStorage']){
        CONSOLE.prop.throw(STORAGE[type].clear, 'type', 'all');
    }

    let storage = window[type];

    storage.clear();

    return this;
}


module.exports = STORAGE;